UPDATE ${tableName}
SET
    filename = #{duplicateImportMetadata.filename},
    extname = #{duplicateImportMetadata.extname},
    update_time = #{duplicateImportMetadata.updateTime},
    upload_id = #{duplicateImportMetadata.uploadId},
    original_zip_name = #{duplicateImportMetadata.originalZipName},
    operator = #{duplicateImportMetadata.operator}
WHERE content_sha256 = #{contentSha256}

UPDATE ${tableName}
SET
    content_sha256 = #{backfillMetadata.contentSha256},
    file_size = #{backfillMetadata.fileSize},
    upload_id = #{backfillMetadata.uploadId},
    original_zip_name = #{backfillMetadata.originalZipName},
    operator = #{backfillMetadata.operator},
    update_time = #{backfillMetadata.updateTime}
WHERE voice_code = #{voiceCode}
